import { Adm } from './Adm';
import { Aluno } from './Aluno';
import { Permissao, parsePermissao } from './Permissao';
import { Professor } from './Professor';
import { PerfilDb, perfilDbParaDados, Usuario } from './Usuario';

export function criarUsuarioDePerfil(row: PerfilDb): Usuario {
  const base = perfilDbParaDados(row);
  const permissao = parsePermissao(row.permissao || row.role);

  switch (permissao) {
    case Permissao.ADM:
      return new Adm({
        ...base,
        codigo: row.codigo,
        telefone: row.telefone,
        dataNascimento: row.data_nascimento,
      });
    case Permissao.Professor:
      return new Professor({
        ...base,
        formacao: row.formacao,
      });
    default:
      return new Aluno({
        ...base,
        matricula: row.matricula,
        curso: row.curso,
      });
  }
}
